js:
const swiper4 = new Swiper('.swiper-type-4', {
  direction: 'horizontal',
  loop: true,
  autoplay: {
    delay: 3000,
    disableOnInteraction: true,
  },
  pagination: {
    el: '.pagination-4',
    type: 'fraction',
  },
  navigation: {
    nextEl: '.btn-next-4',
    prevEl: '.btn-prev-4',
  },
});

css:
/* Swiper Type 04 Styles */
.swiper-type-4 {
  width: 100%;
  border-radius: 20px;
  overflow: hidden;
}

.pagination-4 {
  font-family: 'Outfit', sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: #64748b !important;
  background-color: #f1f5f9;
  padding: 4px 12px;
  border-radius: 20px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 3px;
  width: auto !important;
}

.pagination-4 .swiper-pagination-current {
  color: #6366f1;
  font-weight: 700;
}

.pagination-4 .swiper-pagination-total {
  color: #64748b;
}
